mapper.select:
SELECT 'H' AS statisticalType, '待签约' AS STATUS, ( SELECT COUNT( 1 ) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'B' AND con.status = 'D' AND con.seal_flg = FALSE
) AS buyNum, ( SELECT COUNT( 1 ) FROM t_ctr_dcsx dcsx WHERE dcsx.enterprise_id = 44 AND dcsx.business_type = 'ZY-BB' AND dcsx.status !='C' AND dcsx.seal_flg = FALSE
) AS dcsxNum, ( SELECT COUNT( 1 ) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'S' AND con.status = 'D' AND con.seal_flg = FALSE
) AS sellNum, '已审批、未签约' AS logicalDeclaration UNION ALL
SELECT 'I' AS statisticalType, '待入库' AS STATUS, ( SELECT COUNT( 1 ) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.contract_type='B' AND con.business_type = 'ZY-BB' AND con.contract_status !='C' AND con.seal_flg = TRUE AND con.total_number > con.warehouse_number
) AS buyNum, '' AS dcsxNum, '' AS sellNum, '已签约、未全部入库' AS logicalDeclaration UNION ALL
SELECT 'J' AS statisticalType, '待出库' AS STATUS, '' AS buyNum, '' AS dcsxNum, ( SELECT COUNT( 1 ) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.contract_type='S' AND con.business_type = 'ZY-BB' AND con.contract_status !='C' AND con.seal_flg = TRUE AND con.total_number > con.warehouse_number
) AS sellNum, '已签约、未全部出库' AS logicalDeclaration UNION ALL
SELECT 'K' AS statisticalType, '待确认收货' AS STATUS, '' AS buyNum, ( SELECT COUNT(1) FROM t_ctr_dcsx dcsx left JOIN t_ctr_contract con ON dcsx.approve_id = con.approve_id WHERE dcsx.enterprise_id = 44 AND con.contract_type='S' AND con.business_type = 'ZY-BB' AND con.status != 'C' AND con.seal_flg = TRUE AND con.warehouse_number >= con.total_number AND dcsx.total_number > dcsx.confirm_receive_number
) AS dcsxNum, ( SELECT COUNT( 1 ) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.contract_type='S' AND con.business_type = 'ZY-BB' AND con.contract_status !='C' AND con.seal_flg = TRUE AND con.warehouse_number >= con.total_number AND con.confirm_receipt_flg = FALSE
) AS sellNum, '已出库、未确认收货' AS logicalDeclaration UNION ALL
SELECT 'L' AS statisticalType, '待付款' AS STATUS, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'B' AND con.contract_status != 'C' AND con.seal_flg = TRUE AND con.total_amount > con.dealed_amount
) AS buyNum, ( SELECT COUNT( 1 ) FROM t_ctr_dcsx dcsx WHERE dcsx.enterprise_id = 44 AND dcsx.business_type = 'ZY-BB' AND dcsx.status !='C' AND dcsx.seal_flg = TRUE AND dcsx.total_amount > dcsx.dealed_amount
) AS dcsxNum, '' AS sellNum, '已签约、未全部付款' AS logicalDeclaration UNION ALL
SELECT 'M' AS statisticalType, '待收款' AS STATUS, '' AS buyNum, '' AS dcsxNum, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'S' AND con.contract_status != 'C' AND con.seal_flg = TRUE AND con.total_amount > con.dealed_amount
) AS sellNum, '已签约、未全部收款' AS logicalDeclaration UNION ALL SELECT 'N' AS statisticalType, '待收票' AS STATUS, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'B' AND con.contract_status != 'C' AND con.seal_flg = TRUE AND con.warehouse_number = con.total_number AND con.total_amount > con.billed_amount
) AS buyNum, (SELECT COUNT( 1 ) FROM t_ctr_dcsx dcsx JOIN t_bs_company_our our ON dcsx.our_company_name = our.company_name WHERE dcsx.enterprise_id = 44 AND dcsx.business_type = 'ZY-BB' AND our.our_company_flag=true AND dcsx.status !='C' AND dcsx.seal_flg = TRUE AND dcsx.total_amount > dcsx.billed_amount
) AS dcsxNum, '' AS sellNum, '采购：已入库、未全部收票；中游：已签约、未全部收票' AS logicalDeclaration UNION ALL
SELECT 'O' AS statisticalType, '待开票' AS STATUS, '' AS buyNum, (SELECT COUNT( 1 ) FROM t_ctr_dcsx dcsx JOIN t_bs_company_our our ON dcsx.company_name = our.company_name WHERE dcsx.enterprise_id = 44 AND dcsx.business_type = 'ZY-BB' AND our.our_company_flag=true AND dcsx.status !='C' AND dcsx.seal_flg = TRUE AND dcsx.total_amount > dcsx.invoice_bill_amount
) AS dcsxNum, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'S' AND con.contract_status != 'C' AND con.seal_flg = TRUE AND con.warehouse_number = con.total_number AND con.total_amount > con.billed_amount
) AS sellNum, '已出库、未全部开票' AS logicalDeclaration UNION ALL SELECT 'P' AS statisticalType, '已完成' AS STATUS, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'B' AND con.contract_status != 'C' AND con.seal_flg = TRUE AND con.dealed_amount = con.total_amount AND con.billed_amount = con.total_amount AND con.warehouse_number = con.total_number AND con.breach_amount = con.receive_breach_amount
) AS buyNum, ( SELECT COUNT( 1 ) FROM t_ctr_dcsx dcsx WHERE dcsx.enterprise_id = 44 AND dcsx.business_type = 'ZY-BB' AND dcsx.status !='C' AND dcsx.seal_flg = TRUE AND dcsx.billed_amount >= dcsx.total_amount AND dcsx.invoice_bill_amount >= dcsx.total_amount AND dcsx.dealed_amount >= dcsx.total_amount AND dcsx.receive_amount >= dcsx.total_amount AND dcsx.confirm_receive_number >= dcsx.total_number
) AS dcsxNum, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'S' AND con.contract_status != 'C' AND con.seal_flg = TRUE AND con.dealed_amount = con.total_amount AND con.billed_amount = con.total_amount AND con.warehouse_number = con.total_number AND con.breach_amount = con.receive_breach_amount
) AS sellNum, '同时满足（已收/付款、已开/收票、已收/发货，没有罚金）判定已完成' AS logicalDeclaration UNION ALL
SELECT 'Q' AS statisticalType, '作废' AS STATUS, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'B' AND con.contract_status = 'C'
) AS buyNum, ( SELECT COUNT( 1 ) FROM t_ctr_dcsx dcsx WHERE dcsx.enterprise_id = 44 AND dcsx.business_type = 'ZY-BB' AND dcsx.status ='C'
) AS dcsxNum, ( SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'S' AND con.contract_status = 'C'
) AS sellNum, '手动操作' AS logicalDeclaration UNION ALL
SELECT 'R' AS statisticalType, '罚金不足' AS STATUS, '' AS buyNum, '' AS dcsxNum, (SELECT COUNT(1) FROM t_ctr_contract con WHERE con.enterprise_id = 44 AND con.business_type = 'ZY-BB' AND con.contract_type = 'S' AND con.contract_status != 'C' AND con.seal_flg = TRUE AND con.breach_amount > con.receive_breach_amount
) AS sellNum, '合同产生罚金，还有未收到的罚金' AS logicalDeclaration
